"""Главный agent loop: tool calling до final_answer или лимита итераций."""
from __future__ import annotations

import json
import logging
import sys
from dataclasses import dataclass, field
from typing import Any

from .config import Config
from .db import OracleClient
from .llm import LLMClient
from .prompts import build_system_prompt
from .tools import TOOL_SPECS, ToolRegistry, serialise_tool_result

logger = logging.getLogger(__name__)


@dataclass
class AgentResult:
    answer: str
    iterations: int
    sql: str | None = None
    supporting_data: dict[str, Any] | None = None
    trace: list[dict[str, Any]] = field(default_factory=list)

    def to_dict(self) -> dict[str, Any]:
        return {
            "answer": self.answer,
            "iterations": self.iterations,
            "sql": self.sql,
            "supporting_data": self.supporting_data,
            "trace": self.trace,
        }


class Agent:
    def __init__(self, cfg: Config | None = None) -> None:
        self.cfg = cfg or Config.load()
        self.oracle = OracleClient(self.cfg)
        self.llm = LLMClient(self.cfg)

    def run(self, question: str, *, verbose: bool = False) -> AgentResult:
        tools = ToolSpecsBundle(TOOL_SPECS)
        registry = ToolRegistry(self.oracle)

        messages: list[dict[str, Any]] = [
            {"role": "system", "content": build_system_prompt()},
            {"role": "user", "content": question.strip()},
        ]
        trace: list[dict[str, Any]] = []
        iteration = 0

        for iteration in range(1, self.cfg.max_iterations + 1):
            if verbose:
                print(f"[iter {iteration}] → LLM", file=sys.stderr)
            response = self.llm.chat(
                messages=messages,
                tools=tools.specs,
                tool_choice="auto" if iteration < self.cfg.max_iterations else "none",
            )
            choice = response.choices[0]
            msg = choice.message
            assistant_msg: dict[str, Any] = {"role": "assistant"}
            if msg.content:
                assistant_msg["content"] = msg.content
            else:
                assistant_msg["content"] = None
            if msg.tool_calls:
                assistant_msg["tool_calls"] = [
                    {
                        "id": tc.id,
                        "type": "function",
                        "function": {
                            "name": tc.function.name,
                            "arguments": tc.function.arguments,
                        },
                    }
                    for tc in msg.tool_calls
                ]
            messages.append(assistant_msg)

            if not msg.tool_calls:
                # Модель не позвала тулзу. Если final_answer уже был вызван — отдаём ответ.
                if registry.state.final_text:
                    break
                # Иначе считаем content фолбэком, добавляем подсказку и продолжаем.
                fallback = (msg.content or "").strip()
                if fallback:
                    trace.append({"type": "assistant_text", "content": fallback})
                if iteration >= self.cfg.max_iterations:
                    return self._build_result(
                        registry,
                        trace,
                        iteration,
                        fallback_text=fallback
                        or "Не удалось получить ответ от модели — лимит итераций исчерпан.",
                    )
                messages.append(
                    {
                        "role": "user",
                        "content": (
                            "Не забудь: финальный ответ выдаётся ТОЛЬКО через tool final_answer. "
                            "Если данные уже собраны — вызови final_answer."
                        ),
                    }
                )
                continue

            for tc in msg.tool_calls:
                name = tc.function.name
                raw_args = tc.function.arguments or "{}"
                try:
                    args = json.loads(raw_args) if isinstance(raw_args, str) else dict(raw_args)
                except json.JSONDecodeError as exc:
                    args = {}
                    tool_payload = {"error": f"bad_json_arguments: {exc}", "raw": raw_args}
                else:
                    tool_payload = registry.call(name, args)

                trace_entry = {
                    "type": "tool_call",
                    "iteration": iteration,
                    "name": name,
                    "arguments": args,
                    "result_preview": _preview(tool_payload),
                }
                trace.append(trace_entry)
                if verbose:
                    print(
                        f"[iter {iteration}] tool={name} args={_preview(args)} "
                        f"→ {_preview(tool_payload)}",
                        file=sys.stderr,
                    )
                messages.append(
                    {
                        "role": "tool",
                        "tool_call_id": tc.id,
                        "name": name,
                        "content": serialise_tool_result(tool_payload),
                    }
                )

            if registry.state.final_text:
                break

        return self._build_result(registry, trace, iteration)

    def _build_result(
        self,
        registry: ToolRegistry,
        trace: list[dict[str, Any]],
        iterations: int,
        fallback_text: str | None = None,
    ) -> AgentResult:
        answer = registry.state.final_text or fallback_text or (
            "Агент не смог сформировать финальный ответ — "
            "проверь логи (verbose) или увеличь max_iterations."
        )
        return AgentResult(
            answer=answer,
            iterations=iterations,
            sql=registry.state.last_sql,
            supporting_data=registry.state.final_supporting,
            trace=trace,
        )


@dataclass
class ToolSpecsBundle:
    specs: list[dict[str, Any]]


def _preview(obj: Any, limit: int = 220) -> str:
    text = json.dumps(obj, ensure_ascii=False, default=str)
    if len(text) <= limit:
        return text
    return text[:limit] + f"...[+{len(text) - limit} chars]"


def run(question: str, *, verbose: bool = False, cfg: Config | None = None) -> AgentResult:
    """Удобный one-shot helper."""
    return Agent(cfg).run(question, verbose=verbose)

"""Реализация инструментов агента + их JSON-схемы для OpenAI tool calling."""
from __future__ import annotations

import json
import logging
from dataclasses import dataclass
from typing import Any, Callable

from .db import OracleClient, UnsafeSqlError, assert_safe_select
from .schema import describe_table, list_tables
from .validate import Expectations, validate

logger = logging.getLogger(__name__)


# JSON-схемы tools — отправляются в LLM через параметр `tools`.
TOOL_SPECS: list[dict[str, Any]] = [
    {
        "type": "function",
        "function": {
            "name": "inspect_schema",
            "description": (
                "Получить описание таблицы (бизнес-семантика полей, единицы измерения, "
                "категории, примеры SQL). Вызови до написания SQL. "
                "Доступная таблица: 'client_product'."
            ),
            "parameters": {
