                "properties": {
                    "table": {
                        "type": "string",
                        "description": "Имя таблицы. По умолчанию — client_product.",
                        "default": "client_product",
                    }
                },
                "additionalProperties": False,
            },
        },
    },
    {
        "type": "function",
        "function": {
            "name": "execute_sql",
            "description": (
                "Выполнить SELECT-запрос на Oracle и получить таблицу результатов. "
                "Разрешён только один SELECT/WITH без ';' и DML/DDL. "
                "Используй Oracle-синтаксис (DATE 'YYYY-MM-DD', FETCH FIRST N ROWS ONLY, EXTRACT)."
            ),
