                            "max_rows": {"type": ["integer", "null"]},
                            "required_columns": {"type": "array", "items": {"type": "string"}},
                            "non_null_columns": {"type": "array", "items": {"type": "string"}},
                            "numeric_ranges": {"type": "object"},
