@dataclass
class ToolState:
    """Состояние между tool-вызовами в рамках одной сессии агента."""
    last_sql: str | None = None
    last_result_dict: dict[str, Any] | None = None
    final_text: str | None = None
    final_supporting: dict[str, Any] | None = None


class ToolRegistry:
    """Диспетчер tool-вызовов. Хранит ссылку на БД и состояние сессии."""

    def __init__(self, oracle: OracleClient) -> None:
        self._oracle = oracle
        self.state = ToolState()
        self._handlers: dict[str, Callable[[dict[str, Any]], dict[str, Any]]] = {
            "inspect_schema": self._inspect_schema,
            "execute_sql": self._execute_sql,
            "validate_result": self._validate_result,
            "final_answer": self._final_answer,
        }

    def call(self, name: str, arguments: dict[str, Any]) -> dict[str, Any]:
        handler = self._handlers.get(name)
        if handler is None:
            return {"error": f"Неизвестный инструмент: {name}", "available": list(self._handlers)}
        try:
            return handler(arguments or {})
        except Exception as exc:  # pylint: disable=broad-except
            logger.exception("Tool %s failed", name)
            return {"error": f"{type(exc).__name__}: {exc}"}

    # ----- handlers -----

    def _inspect_schema(self, args: dict[str, Any]) -> dict[str, Any]:
        table = args.get("table") or "client_product"
        if table not in list_tables():
            return {
                "error": f"Таблица {table!r} не найдена.",
                "available_tables": list_tables(),
            }
        return describe_table(table)

    def _execute_sql(self, args: dict[str, Any]) -> dict[str, Any]:
        sql = (args.get("sql") or "").strip()
        if not sql:
            return {"error": "Параметр 'sql' обязателен."}
        try:
            assert_safe_select(sql)
        except UnsafeSqlError as exc:
            return {"error": f"unsafe_sql: {exc}"}
        max_rows = args.get("max_rows")
        try:
            result = self._oracle.run_select(sql, max_rows=max_rows)
        except UnsafeSqlError as exc:  # на всякий случай — guard повторно
            return {"error": f"unsafe_sql: {exc}"}
        except Exception as exc:  # oracledb.DatabaseError + сетевые
            return {"error": f"oracle_error: {type(exc).__name__}: {exc}"}
        self.state.last_sql = sql
        self.state.last_result_dict = result.to_dict()
        return {
            "sql": sql,
            **result.to_dict(),
            # Подсказка модели — если результат большой, она увидит truncated=True.
            "note": (
                "Покажи первые строки результата пользователю, если их немного. "
                "Не выдавай ответ без validate_result."
            ),
        }

    def _validate_result(self, args: dict[str, Any]) -> dict[str, Any]:
        if not self.state.last_result_dict:
            return {"error": "Нет результата SQL для валидации — сначала вызови execute_sql."}
        expectations = Expectations.from_dict(args.get("expectations"))
        # Reconstruct QueryResult-like shim for validator.
        from .db import QueryResult  # local import to avoid cycles
        last = self.state.last_result_dict
        result = QueryResult(
            columns=list(last["columns"]),
            rows=[list(r) for r in last["rows"]],
            row_count=int(last["row_count"]),
            truncated=bool(last["truncated"]),
        )
        report = validate(result, expectations)
        return report.to_dict()

    def _final_answer(self, args: dict[str, Any]) -> dict[str, Any]:
        text = (args.get("text") or "").strip()
        if not text:
            return {"error": "Параметр 'text' обязателен и не должен быть пустым."}
        self.state.final_text = text
        supporting = args.get("supporting_data")
        if isinstance(supporting, dict):
            self.state.final_supporting = supporting
        return {"accepted": True}


def serialise_tool_result(payload: dict[str, Any], max_chars: int = 12000) -> str:
    """Serialize tool output для LLM. Урезает раздутые результаты до max_chars."""
    text = json.dumps(payload, ensure_ascii=False, default=str)
    if len(text) <= max_chars:
        return text
    head = text[: max_chars - 200]
    return head + f"\n...[обрезано: всего {len(text)} символов, показаны первые {max_chars - 200}]"

"""Тонкий wrapper над oracledb для SELECT-запросов."""
from __future__ import annotations

import logging
from dataclasses import dataclass
from datetime import date, datetime
from decimal import Decimal
from typing import Any

import oracledb

from .config import Config

logger = logging.getLogger(__name__)


_FORBIDDEN_TOKENS = (
    "insert ",
    "update ",
    "delete ",
    "merge ",
    "drop ",
    "alter ",
    "truncate ",
    "create ",
    "grant ",
    "revoke ",
    "begin ",
    "execute ",
    "exec ",
    "call ",
)


class UnsafeSqlError(ValueError):
    """SELECT-only гард — любой DML/DDL отклоняется до отправки в БД."""


@dataclass
class QueryResult:
    columns: list[str]
    rows: list[list[Any]]
    row_count: int
    truncated: bool

    def to_dict(self) -> dict[str, Any]:
        return {
            "columns": self.columns,
            "rows": self.rows,
            "row_count": self.row_count,
            "truncated": self.truncated,
        }


def assert_safe_select(sql: str) -> None:
    """Базовая проверка: запрос — single SELECT/WITH без DML/DDL."""
    stripped = sql.strip().rstrip(";").strip()
    if not stripped:
        raise UnsafeSqlError("Пустой SQL-запрос.")
    if ";" in stripped:
        raise UnsafeSqlError("Запрещено несколько statements (символ ';' внутри SQL).")
    low = stripped.lower()
    if not (low.startswith("select") or low.startswith("with")):
        raise UnsafeSqlError("Разрешены только SELECT/WITH запросы.")
    padded = " " + low + " "
    for tok in _FORBIDDEN_TOKENS:
        if " " + tok in padded:
            raise UnsafeSqlError(f"Запрещённая конструкция в SQL: {tok.strip()!r}.")


def _coerce(value: Any) -> Any:
    if isinstance(value, Decimal):
        # Чтобы json-сериализация работала и числа было удобно сравнивать.
        if value == value.to_integral_value():
            return int(value)
        return float(value)
    if isinstance(value, (datetime, date)):
        return value.isoformat()
    if isinstance(value, bytes):
        return value.decode("utf-8", errors="replace")
    return value


class OracleClient:
    """Подключение на запрос (XE — лёгкое, persistent pool не нужен)."""

    def __init__(self, cfg: Config) -> None:
        self._cfg = cfg

    def _connect(self) -> oracledb.Connection:
        return oracledb.connect(
            user=self._cfg.oracle_user,
            password=self._cfg.oracle_password,
            dsn=self._cfg.oracle_dsn,
        )

    def run_select(self, sql: str, max_rows: int | None = None) -> QueryResult:
        assert_safe_select(sql)
        limit = max_rows or self._cfg.max_rows
        logger.info("Executing SQL (limit=%d): %s", limit, sql.replace("\n", " ")[:400])
        with self._connect() as conn:
            cur = conn.cursor()
            cur.execute(sql)
            columns: list[str] = (
                [str(c[0]) for c in cur.description] if cur.description else []
            )
            raw_rows = cur.fetchmany(limit + 1)
            truncated = len(raw_rows) > limit
            rows = [[_coerce(v) for v in row] for row in raw_rows[:limit]]
            return QueryResult(
                columns=columns,
                rows=rows,
                row_count=len(rows),
                truncated=truncated,
            )

"""Тонкий wrapper над OpenAI-совместимым клиентом Ollama."""
from __future__ import annotations

import logging
from typing import Any

from openai import OpenAI

from .config import Config

logger = logging.getLogger(__name__)


class LLMClient:
    def __init__(self, cfg: Config) -> None:
        self._cfg = cfg
        self._client = OpenAI(api_key=cfg.api_key, base_url=cfg.api_url)

    @property
    def sql_model(self) -> str:
        return self._cfg.sql_model

    @property
    def response_model(self) -> str:
        return self._cfg.response_model

    def chat(
        self,
        messages: list[dict[str, Any]],
        *,
        model: str | None = None,
        tools: list[dict[str, Any]] | None = None,
        tool_choice: str | dict[str, Any] = "auto",
        temperature: float = 0.0,
    ) -> Any:
        kwargs: dict[str, Any] = {
            "model": model or self._cfg.sql_model,
            "messages": messages,
            "temperature": temperature,
        }
        if tools:
            kwargs["tools"] = tools
            kwargs["tool_choice"] = tool_choice
        logger.debug("LLM call: model=%s tools=%d", kwargs["model"], len(tools or []))
        return self._client.chat.completions.create(**kwargs)

"""Sanity-check результатов SQL: размер, ненулевые ключи, разумные диапазоны."""
from __future__ import annotations

from dataclasses import dataclass, field
from typing import Any

from .db import QueryResult


@dataclass
class Expectations:
    min_rows: int = 0
    max_rows: int | None = None
    required_columns: list[str] = field(default_factory=list)
    non_null_columns: list[str] = field(default_factory=list)
    numeric_ranges: dict[str, tuple[float | None, float | None]] = field(default_factory=dict)
    note: str | None = None

    @classmethod
    def from_dict(cls, data: dict[str, Any] | None) -> "Expectations":
        data = data or {}
        ranges_in = data.get("numeric_ranges") or {}
        ranges: dict[str, tuple[float | None, float | None]] = {}
        for col, bounds in ranges_in.items():
            if isinstance(bounds, dict):
                ranges[col] = (bounds.get("min"), bounds.get("max"))
            elif isinstance(bounds, (list, tuple)) and len(bounds) == 2:
                ranges[col] = (bounds[0], bounds[1])
        return cls(
            min_rows=int(data.get("min_rows", 0)),
            max_rows=data.get("max_rows"),
            required_columns=list(data.get("required_columns") or []),
            non_null_columns=list(data.get("non_null_columns") or []),
            numeric_ranges=ranges,
            note=data.get("note"),
        )


@dataclass
class ValidationReport:
    ok: bool
    issues: list[str]
    warnings: list[str]
    summary: dict[str, Any]

    def to_dict(self) -> dict[str, Any]:
        return {
            "ok": self.ok,
            "issues": self.issues,
            "warnings": self.warnings,
            "summary": self.summary,
        }


def _column_index(result: QueryResult, name: str) -> int | None:
    upper = name.upper()
    for idx, col in enumerate(result.columns):
        if col.upper() == upper:
            return idx
    return None


def validate(result: QueryResult, expectations: Expectations) -> ValidationReport:
    issues: list[str] = []
    warnings: list[str] = []
    summary: dict[str, Any] = {
        "row_count": result.row_count,
        "columns": result.columns,
    }

    if result.truncated:
        warnings.append(
            f"Результат обрезан до {result.row_count} строк — возможно, есть больше данных."
        )

    if result.row_count < expectations.min_rows:
        issues.append(
            f"Слишком мало строк: {result.row_count} < min_rows={expectations.min_rows}."
        )
    if expectations.max_rows is not None and result.row_count > expectations.max_rows:
        warnings.append(
            f"Строк больше ожидаемого: {result.row_count} > max_rows={expectations.max_rows}."
        )

    for col in expectations.required_columns:
        if _column_index(result, col) is None:
            issues.append(f"Отсутствует ожидаемая колонка: {col}.")

    for col in expectations.non_null_columns:
        idx = _column_index(result, col)
        if idx is None:
            issues.append(f"non_null_columns: колонка {col} отсутствует в результате.")
            continue
        null_count = sum(1 for row in result.rows if row[idx] is None)
        summary.setdefault("nulls", {})[col] = null_count
        if null_count == result.row_count and result.row_count > 0:
            issues.append(f"Все значения колонки {col} = NULL — подозрительно.")
        elif null_count > 0:
            warnings.append(f"В колонке {col} есть {null_count} NULL значений.")

    for col, (lo, hi) in expectations.numeric_ranges.items():
        idx = _column_index(result, col)
        if idx is None:
            issues.append(f"numeric_ranges: колонка {col} отсутствует в результате.")
            continue
        numeric_vals = [
            row[idx] for row in result.rows if isinstance(row[idx], (int, float))
        ]
        if not numeric_vals:
            warnings.append(f"В колонке {col} нет числовых значений — проверка диапазона пропущена.")
            continue
        col_min, col_max = min(numeric_vals), max(numeric_vals)
        summary.setdefault("ranges", {})[col] = {"min": col_min, "max": col_max}
        if lo is not None and col_min < lo:
            issues.append(f"{col}: минимум {col_min} ниже допустимого {lo}.")
        if hi is not None and col_max > hi:
            issues.append(f"{col}: максимум {col_max} выше допустимого {hi}.")

    # Базовый sanity: если есть числовые колонки и все значения NULL — это тоже подозрительно.
    if result.row_count == 0 and expectations.min_rows == 0:
        warnings.append(
            "Запрос вернул 0 строк — проверь корректность условий WHERE и наличие данных за период."
        )

    return ValidationReport(
        ok=not issues,
        issues=issues,
        warnings=warnings,
        summary=summary,
    )

"""Адаптер метаданных таблицы → компактный текст для LLM."""
from __future__ import annotations

from typing import Any

from metadata import get_sql_examples, get_table_metadata


def list_tables() -> list[str]:
    return ["client_product"]


def _format_field(name: str, spec: dict[str, Any]) -> str:
    parts = [f"- {name} ({spec.get('type', '?')})"]
    desc = (spec.get("description") or "").strip()
    if desc:
        # Сжимаем многострочные описания в одну логическую строку.
        desc_one = " ".join(desc.split())
        parts.append(f"  description: {desc_one}")
    category = spec.get("category")
    if category:
        parts.append(f"  category: {category}")
    extras = []
    for key in ("operation_currency", "result_currency_equivalent",
                "aggregation_between_clients", "aggregation_between_month"):
        val = spec.get(key)
        if val and val != "N/A":
            extras.append(f"{key}={val}")
    if extras:
        parts.append("  meta: " + ", ".join(extras))
    if spec.get("is_key"):
        parts.append("  key: true")
    return "\n".join(parts)


def describe_table(table: str = "client_product") -> dict[str, Any]:
    """Структурированное описание таблицы для tool-call'а inspect_schema."""
    meta = get_table_metadata(table)
    fields_block: list[str] = []
    categories: dict[str, list[str]] = {}
    for name, spec in meta["fields"].items():
        cat = spec.get("category") or "Без категории"
        categories.setdefault(cat, []).append(name)
        fields_block.append(_format_field(name, spec))

    examples = get_sql_examples(table)
    examples_text = "\n\n".join(
        f"Q: {ex['question']}\nSQL: {ex['sql'].strip()}" for ex in examples
    )

    return {
        "table": table,
        "description": " ".join(meta["description"].split()),
        "categories": categories,
        "fields_text": "\n".join(fields_block),
        "examples_text": examples_text,
        "field_count": len(meta["fields"]),
    }


